<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const valor=parseFloat(document.getElementById('cc-valor').value);const juros=parseFloat(document.getElementById('cc-juros').value)/100;const meses=parseInt(document.getElementById('cc-meses').value,10);clearError();if(isNaN(valor)||isNaN(juros)||isNaN(meses)||valor<=0||juros<0||meses<=0){showError('Preencha valor, juros e meses com dados válidos.');return;}const parcela=juros===0?valor/meses:(valor*juros)/(1-Math.pow(1+juros,-meses));const total=parcela*meses;document.getElementById('cc-parcela').textContent='R$ '+fmtBRL(parcela);document.getElementById('cc-total').textContent='R$ '+fmtBRL(total);document.getElementById('tool-detail').textContent='Simulação útil para análise de parcelamento e comparação financeira.';showResult('tool-result');}function clearTool(){['cc-valor','cc-juros','cc-meses'].forEach(id=>document.getElementById(id).value='');['cc-parcela','cc-total'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule a fatura antes de copiar o resultado.');return;}copyToClipboard('Parcela estimada: '+document.getElementById('cc-parcela').textContent,button);}
</script>
